from __future__ import print_function
import sys
from kafka import KafkaAdminClient, KafkaException

def createTopic(topicName):  
    admin = KafkaAdminClient('localhost:9092') # Adjust this to your broker list and port 
    
    try:
        topic_list = [{'topic': topicName,'num_partitions' : int(sys.argv[3]), 'replication_factor' : sys.argv[4]} for i in range (int(sys.argv[2])) ]  # Adjust this to your number of topics and partitions
        admin.create_topics(new_topics=topic_list, validate_only=False)  
    except KafkaException as e:    
       print("Failed creating topic",e)     
        
if __name__ == '__main__':  # Adjust this to your main function and arguments.       
    createTopic(sys.argv[1])